class Solution:
    def minimumTimeRequired(self, jobs, k):
        n = len(jobs)
        order = sorted(range(n), key=lambda i: -jobs[i])
        jobs_sorted = [jobs[i] for i in order]
        loads = [0] * k
        best = [sum(jobs)]
        def backtrack(i):
            if i == n:
                m = max(loads)
                if m < best[0]:
                    best[0] = m
                return
            seen = set()
            for w in range(k):
                if loads[w] in seen:
                    continue
                seen.add(loads[w])
                loads[w] += jobs_sorted[i]
                if loads[w] < best[0]:
                    backtrack(i + 1)
                loads[w] -= jobs_sorted[i]
        backtrack(0)
        return best[0]

