from functools import lru_cache

class Solution:
    def minimumTimeRequired(self, jobs, k):
        n = len(jobs)
        full = (1 << n) - 1
        subset_sum = [0] * (1 << n)
        for mask in range(1, 1 << n):
            lsb = mask & (-mask)
            i = lsb.bit_length() - 1
            subset_sum[mask] = subset_sum[mask ^ lsb] + jobs[i]

        @lru_cache(maxsize=None)
        def dp(remaining, workers):
            if remaining == 0:
                return 0
            if workers == 1:
                return subset_sum[remaining]
            best = subset_sum[remaining]
            sub = remaining
            while sub:
                cost = max(subset_sum[sub], dp(remaining ^ sub, workers - 1))
                if cost < best:
                    best = cost
                sub = (sub - 1) & remaining
            return best

        result = dp(full, k)
        dp.cache_clear()
        return result

