var minimumTimeRequired = function(jobs, k) {
    const n = jobs.length;
    const full = (1 << n) - 1;
    const subsetSum = new Array(1 << n).fill(0);
    for (let mask = 1; mask <= full; mask++) {
        const lsb = mask & (-mask);
        const i = Math.round(Math.log2(lsb));
        subsetSum[mask] = subsetSum[mask & (mask - 1)] + jobs[i];
    }
    const memo = new Map();
    function dp(remaining, workers) {
        if (remaining === 0) return 0;
        if (workers === 1) return subsetSum[remaining];
        const key = remaining + ':' + workers;
        if (memo.has(key)) return memo.get(key);
        let best = subsetSum[remaining];
        for (let sub = remaining; sub > 0; sub = (sub - 1) & remaining) {
            const cost = Math.max(subsetSum[sub], dp(remaining ^ sub, workers - 1));
            if (cost < best) best = cost;
        }
        memo.set(key, best);
        return best;
    }
    return dp(full, k);
};
